import React from 'react';
import { Link } from 'react-router-dom';

const Header = () => {
  return (
    <header style={{ backgroundColor: '#282c34', padding: '10px', color: 'white' }}>
      <nav>
        <Link to="/" style={{ margin: '0 10px', color: 'white', textDecoration: 'none' }}>Home</Link>
        <Link to="/login" style={{ margin: '0 10px', color: 'white', textDecoration: 'none' }}>Login</Link>
        <Link to="/register" style={{ margin: '0 10px', color: 'white', textDecoration: 'none' }}>Signup</Link>
      </nav>
    </header>
  );
};

export default Header;
